changeSet.sql:
-- Голосование за треки в очереди комнаты. Каждый пользователь может оставить
-- 1 голос за каждый item очереди. Голос снимается повторным запросом.
CREATE TABLE room_queue_votes (
    queue_id UUID NOT NULL REFERENCES room_queue(id) ON DELETE CASCADE,
    user_id  UUID NOT NULL REFERENCES users(id)      ON DELETE CASCADE,
    voted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (queue_id, user_id)
);

CREATE INDEX idx_room_queue_votes_queue ON room_queue_votes(queue_id);
